{{main other|{{#if:{{Has short description}}||<!--
  -->{{if first display both|{{#invoke:Type in location|main|{{if empty|{{{lake_type|}}}|{{{ocean_type|}}}|{{{type|}}}}}|<!--
      -->{{if empty|{{{location|}}}|{{{basin_countries|}}}|{{{countries|}}}}}|<!--
      -->check-patterns=basin;bay;bight;channel;estuary;gulf;lagoon;lake;loch;ocean;reservoir;river;sea;sound;strait|<--
      -->invalidadd={{if empty|{{#if:{{{lake_type|}}}|lake}}|{{#if:{{{ocean_type|}}}|sea}}|body of water}}}}|<!--
  -->[[Category:Pages using infobox body of water with auto short description]]}}}}}}<!--
-->{{infobox
| child          = {{lc:{{{child|{{{embed|}}}}}}}}
| bodyclass      = vcard
| bodystyle      = {{#ifeq:{{{align}}}|left|float: {{{align}}}; clear: {{{align}}}; margin-left:0; margin-right: 1em; }}
| headerstyle    = border-bottom: #cedeff 1px solid

| abovestyle     = background-color: #cedeff; font-size: 125%;
| aboveclass     = fn org
| above          = {{#if:{{{name|}}}|{{{name}}}|<includeonly>{{PAGENAMEBASE}}</includeonly>}}

<!-- The following is only activated when child = yes or embed = yes -->
| titleclass     = fn org
| title          = {{#ifeq:{{lc:{{{child|{{{embed|}}}}}}}}|yes|{{#if:{{{name|}}}|{{{name}}}|<includeonly>{{PAGENAMEBASE}}</includeonly>}}}}

| subheaderclass = nickname
| subheaderstyle = font-size:100%; border-bottom: 1px solid #cedeff;
| subheader      = {{{other_name|}}}
| subheader2     = {{native name checker|{{{native_name|}}}}}

| imagestyle     = line-height: 1.2; border-bottom: 1px solid #cedeff;

| image    = {{#invoke:InfoboxImage|InfoboxImage|image={{{image|}}}|size={{{image_size|}}}|sizedefault=264px|maxsize=296px|border=yes|alt={{{alt|}}} }}
| caption  = {{{caption|}}}

| image2   = {{#invoke:InfoboxImage|InfoboxImage|image={{{image_map|}}}|size={{{map_size|{{{image_size|}}}}}}|sizedefault=256px|maxsize=296px|border=yes|alt={{{alt_map|}}}}}
| caption2 = {{{caption_map|}}}

| image3   = {{#if:{{both| {{{pushpin_map|}}} | {{{coordinates|}}}{{{coords|}}}{{#property:P625}} }}|
{{location map|{{{pushpin_map|}}}
